[
  {
    "text": "Principal components analysis in Fig. 22 shows that the position of the mouth, anus, and posterior head margin load heavily on PC1, and opercle width and position of anus and anal fin load heavily on PC2.",
    "topic": "Head-shape variation in Sternarchella orthos"
  },
  {
    "text": "The three populations of Sternarchella orthos from the Eastern Amazon (EA), Orinoco (OR), and Western Amazon (WA) show partial separations in the principal components analysis.",
    "topic": "Population separation in Sternarchella orthos"
  },
  {
    "text": "The Eastern Amazon (EA) includes the upper Madeira region on both morphometric and hydrogeographic grounds for Sternarchella orthos.",
    "topic": "Geographic classification of Sternarchella orthos"
  },
  {
    "text": "Fig. 22 presents a principal components analysis (PCA) of head-shape variation in Sternarchella orthos across three hydrogeographic regions of Greater Amazonia.",
    "topic": "Principal components analysis in Sternarchella orthos"
  },
  {
    "text": "Two new species of the deep channel electric fish genus Sternarchella are described in the taxonomic revision.",
    "topic": "New species descriptions in Sternarchella"
  }
]
